import{_ as l,o as r,c as s,ae as i}from"./chunks/framework.C1HfCp8_.js";const h=JSON.parse('{"title":"OpenClaw 架构总览（基于源码的事实对齐版）","description":"","frontmatter":{},"headers":[],"relativePath":"p1-overview/architecture.md","filePath":"p1-overview/architecture.md"}'),t={name:"p1-overview/architecture.md"};function a(c,e,n,o,g,u){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="openclaw-架构总览-基于源码的事实对齐版" tabindex="-1">OpenClaw 架构总览（基于源码的事实对齐版） <a class="header-anchor" href="#openclaw-架构总览-基于源码的事实对齐版" aria-label="Permalink to &quot;OpenClaw 架构总览（基于源码的事实对齐版）&quot;">​</a></h1><p>本文以仓库源码为唯一事实来源，所有断言均附带路径引用（相对仓库根）。避免空泛形容与拟人化描述。</p><h2 id="_1-定位与边界" tabindex="-1">1. 定位与边界 <a class="header-anchor" href="#_1-定位与边界" aria-label="Permalink to &quot;1. 定位与边界&quot;">​</a></h2><ul><li>核心目标：提供可落地的 AI Agent 运行时、消息渠道集成与工具执行体系。</li><li>运行入口：命令行 CLI 与 Gateway 服务并行存在，分别面向本地交互与长连接服务。</li><li>本文不覆盖第三方扩展实现细节，聚焦核心仓库。</li></ul><h2 id="_2-模块总览-目录与职责" tabindex="-1">2. 模块总览（目录与职责） <a class="header-anchor" href="#_2-模块总览-目录与职责" aria-label="Permalink to &quot;2. 模块总览（目录与职责）&quot;">​</a></h2><ul><li>CLI 与命令 <ul><li>入口与装配：src/entry.ts、src/index.ts</li><li>主流程：src/cli/run-main.ts、src/cli/program.ts、src/cli/route.ts</li><li>命令实现：src/commands/*</li></ul></li><li>Agent 与上下文 <ul><li>主循环与工具调用：src/agents/pi-embedded-runner/run.ts</li><li>工具目录与适配：src/agents/tool-catalog.ts、src/agents/tools/*</li><li>记忆/上下文接入：src/agents/memory-search.ts、src/context-engine/*</li></ul></li><li>渠道与路由 <ul><li>路由与会话键：src/routing/resolve-route.ts、src/routing/session-key.ts</li><li>渠道注册与公共工具：src/channels/registry.ts</li><li>平台实现：src/telegram、src/discord、src/slack、src/signal、src/imessage、src/web</li></ul></li><li>网关（Gateway） <ul><li>启动与方法集：src/gateway/server.impl.ts、src/gateway/server-methods.ts、src/gateway/server-http.ts</li><li>运行期集成：src/gateway/server-ws-runtime.ts、src/gateway/server-startup.ts</li></ul></li><li>媒体与浏览器 <ul><li>媒体服务：src/media/server.ts、src/media/store.ts、src/media/fetch.ts</li><li>浏览器与自动化：src/browser/*</li></ul></li><li>配置与日志 <ul><li>配置入口与校验：src/config/config.ts、src/config/io.ts、src/config/validation.ts</li><li>日志统一入口：src/logging.ts、src/logging/logger.ts、src/logging/subsystem.ts</li></ul></li></ul><p>以上目录在不同版本可能存在精简/重命名，请以实际仓库为准。</p><h2 id="_3-典型调用链" tabindex="-1">3. 典型调用链 <a class="header-anchor" href="#_3-典型调用链" aria-label="Permalink to &quot;3. 典型调用链&quot;">​</a></h2><ul><li>CLI → Agent → 渠道发送 <ol><li>入口：src/entry.ts → 动态导入 src/cli/run-main.ts</li><li>组装 CLI：src/cli/program.ts 注册命令 → 例如 src/commands/agent.ts</li><li>Agent 执行：src/agents/pi-embedded-runner/run.ts（工具在 src/agents/tools/*）</li><li>出站发送：src/infra/outbound/*（实现因版本而异）→ 各渠道 send（如 src/telegram/send.ts）</li></ol></li><li>Gateway → Handler → Agent <ol><li>服务：src/gateway/server.impl.ts 启动 WS/HTTP</li><li>分发：src/gateway/server-methods.ts 聚合各方法</li><li>触发：方法内根据请求调度 Agent 或系统服务</li></ol></li></ul><h2 id="_4-关键文件-查阅起点" tabindex="-1">4. 关键文件（查阅起点） <a class="header-anchor" href="#_4-关键文件-查阅起点" aria-label="Permalink to &quot;4. 关键文件（查阅起点）&quot;">​</a></h2><ul><li>CLI：src/entry.ts、src/cli/run-main.ts、src/cli/program.ts</li><li>Agent：src/agents/pi-embedded-runner/run.ts、src/agents/tool-catalog.ts、src/agents/tools/*</li><li>路由：src/routing/resolve-route.ts、src/routing/session-key.ts</li><li>渠道：src/channels/registry.ts、各平台 send/monitor 文件</li><li>网关：src/gateway/server.impl.ts、src/gateway/server-methods.ts</li><li>配置：src/config/config.ts、src/config/validation.ts</li><li>日志：src/logging.ts、src/logging/logger.ts</li></ul><h2 id="_5-可复现阅读路径" tabindex="-1">5. 可复现阅读路径 <a class="header-anchor" href="#_5-可复现阅读路径" aria-label="Permalink to &quot;5. 可复现阅读路径&quot;">​</a></h2><ul><li>从 CLI 入手：阅读 src/entry.ts → src/cli/run-main.ts，了解命令如何注册与解析。</li><li>追踪一次消息发送：从某个命令触发到 Agent 执行，再到出站发送与渠道落地。</li><li>对照文档目录阅读：docs/* 下的配置、网关和渠道说明与源码相互印证。</li></ul><h2 id="_6-写作规范与引用" tabindex="-1">6. 写作规范与引用 <a class="header-anchor" href="#_6-写作规范与引用" aria-label="Permalink to &quot;6. 写作规范与引用&quot;">​</a></h2><ul><li>事实优先：每个结论配套“路径引用”；当版本差异导致文件缺失时，标注“版本差异，读者以实际分支为准”。</li><li>命名一致：产品名“OpenClaw”，命令/包名/配置键“openclaw”。</li><li>示例最小化：只保留可复现的最小路径与命令，不做臆测性拓展。</li></ul><p>（本章将随仓库结构演进持续更新）</p>',16)])])}const m=l(t,[["render",a]]);export{h as __pageData,m as default};
